#!/usr/bin/env python3
"""
bench_real_whisper_gkq.py — Empirical GKQ quality sweep on REAL Whisper weights.

Loads whisper-tiny (and base if present) from safetensors, runs quantize→dequant
for rank sweep k ∈ {1,2,3,4,8,16,32,64} × variance_threshold {0.999, 0.9999},
measures per-tensor Frobenius relative error and cosine similarity, reports size.

Uses the repo's actual GKQ quantization path from quantize-whisper-weights.py
and gkq_v2_format.py — specifically the signed-uint8 offset-128 encoding
in reconstruct_spectral() rather than the older unsigned version in
WhisperGKQQuantizer._quantize_matrix() (the v2 format is the production path).

Output: numeric table + per-tensor-type breakdown + verdict.
"""

from __future__ import annotations

import sys
import os
from pathlib import Path
from typing import Dict, List, Optional, Tuple

import numpy as np
from safetensors.numpy import load_file

# ── repo paths ────────────────────────────────────────────────────────────────
HERE = Path(__file__).resolve().parent
sys.path.insert(0, str(HERE))

TINY_PATH  = Path("./whisper-tiny-hf-root/model.safetensors")
BASE_PATH  = Path("./whisper-base-hf-root/model.safetensors")

# Q8 reference sizes (known, proven exact parity per task brief)
Q8_SIZES = {"tiny": 37.8, "base": 72.6}  # MB (approximate; whisper-tiny is 38, base 73)

# Sweep parameters
RANKS = [1, 2, 3, 4, 8, 16, 32, 64]
VARIANCE_THRESHOLDS = [0.999, 0.9999]


# ── quantize one 2D matrix at a fixed rank k ─────────────────────────────────

def gkq_quantize_at_rank(W: np.ndarray, k: int) -> Tuple[np.ndarray, np.ndarray, np.ndarray,
                                                           float, float, float]:
    """SVD truncation → offset-128 signed uint8 quant (matches gkq_v2_format reconstruct_spectral).
    Returns (U_q8, sigma_q8, Vt_q8, u_max, sigma_max, v_max).
    """
    W = W.astype(np.float32)
    try:
        U, sigma, Vt = np.linalg.svd(W, full_matrices=False)
    except np.linalg.LinAlgError:
        # fallback: return zero reconstruction
        k_eff = min(k, min(W.shape))
        U_q8 = np.full((W.shape[0], k_eff), 128, dtype=np.uint8)
        s_q8 = np.zeros(k_eff, dtype=np.uint8)
        Vt_q8 = np.full((k_eff, W.shape[1]), 128, dtype=np.uint8)
        return U_q8, s_q8, Vt_q8, 0.0, 0.0, 0.0

    k_eff = min(k, len(sigma))
    U_k    = U[:, :k_eff]
    sig_k  = sigma[:k_eff]
    Vt_k   = Vt[:k_eff, :]

    # Signed offset-128 encoding (matching reconstruct_spectral in gkq_v2_format.py)
    u_max = float(np.abs(U_k).max()) + 1e-12
    v_max = float(np.abs(Vt_k).max()) + 1e-12
    s_max = float(sig_k.max()) + 1e-12

    # U, Vt: signed range → map to [1,255] via offset 128, range 127
    U_q8  = np.clip(np.round(U_k  / u_max * 127 + 128), 0, 255).astype(np.uint8)
    Vt_q8 = np.clip(np.round(Vt_k / v_max * 127 + 128), 0, 255).astype(np.uint8)
    # sigma: unsigned, positive → map to [0, 255]
    s_q8  = np.clip(np.round(sig_k / s_max * 255), 0, 255).astype(np.uint8)

    return U_q8, s_q8, Vt_q8, u_max, s_max, v_max


def gkq_reconstruct(U_q8, s_q8, Vt_q8, u_max, s_max, v_max) -> np.ndarray:
    """Dequantize exactly as gkq_v2_format.reconstruct_spectral()."""
    U   = ((U_q8.astype(np.float32)  - 128.0) / 127.0) * u_max
    sig = (s_q8.astype(np.float32)   / 255.0) * s_max
    Vt  = ((Vt_q8.astype(np.float32) - 128.0) / 127.0) * v_max
    return (U * sig[np.newaxis, :]) @ Vt


def variance_rank(W: np.ndarray, threshold: float) -> int:
    """Return rank needed to capture `threshold` fraction of singular value energy."""
    W32 = W.astype(np.float32)
    try:
        _, sigma, _ = np.linalg.svd(W32, full_matrices=False, compute_uv=True)
    except np.linalg.LinAlgError:
        return 1
    energy = sigma ** 2
    total  = energy.sum()
    if total < 1e-20:
        return 1
    cumulative = np.cumsum(energy) / total
    where = np.searchsorted(cumulative, threshold)
    return int(min(where + 1, len(sigma)))


def classify_tensor(name: str, ndim: int) -> str:
    """Classify a tensor by type for per-group analysis."""
    if ndim > 2:
        return "conv"
    if ndim == 1:
        return "bias/norm"
    n = name.lower()
    if "embed" in n:
        return "embedding"
    if any(x in n for x in ["q_proj", "k_proj", "v_proj", "out_proj",
                              "query", "key", "value"]):
        return "attention"
    if any(x in n for x in ["fc1", "fc2", "mlp", "ffn", "ff"]):
        return "ffn"
    if "layer_norm" in n or "ln" in n:
        return "layer_norm"
    return "other_2d"


def rel_frob(orig: np.ndarray, recon: np.ndarray) -> float:
    """||W - W'||_F / ||W||_F"""
    denom = float(np.linalg.norm(orig, "fro"))
    if denom < 1e-20:
        return 0.0
    return float(np.linalg.norm(orig - recon, "fro")) / denom


def cosine_sim(orig: np.ndarray, recon: np.ndarray) -> float:
    """Flatten both, compute cosine similarity."""
    a = orig.ravel().astype(np.float64)
    b = recon.ravel().astype(np.float64)
    na, nb = np.linalg.norm(a), np.linalg.norm(b)
    if na < 1e-20 or nb < 1e-20:
        return 0.0
    return float(np.dot(a, b) / (na * nb))


def gkq_bytes_for_tensor(shape: tuple, k: int) -> int:
    """Bytes stored in GKQ for one spectral 2D tensor (q8 arrays only, no overhead)."""
    d_out, d_in = shape[0], shape[1]
    return d_out * k + k + k * d_in   # U_q8 + sigma_q8 + Vt_q8


def gkq_bytes_for_dense(arr: np.ndarray) -> int:
    """Dense tensors (1D bias/norm, conv) stored as fp32 raw bytes."""
    return arr.nbytes


def sweep_model(model_name: str, safetensors_path: Path) -> None:
    print(f"\n{'='*80}")
    print(f"MODEL: {model_name}  ({safetensors_path.name})")
    print(f"{'='*80}")

    weights = load_file(str(safetensors_path))
    total_fp32_bytes = sum(v.nbytes for v in weights.values())
    print(f"FP32 total: {total_fp32_bytes/1e6:.1f} MB  ({len(weights)} tensors)")

    # Separate 2D, 1D, and higher-dim
    mat2d    = {k: v for k, v in weights.items() if v.ndim == 2}
    non_mat  = {k: v for k, v in weights.items() if v.ndim != 2}

    print(f"  2D matrices (GKQ spectral): {len(mat2d)} tensors, "
          f"{sum(v.nbytes for v in mat2d.values())/1e6:.1f} MB")
    print(f"  Non-2D (dense passthrough): {len(non_mat)} tensors, "
          f"{sum(v.nbytes for v in non_mat.values())/1e6:.1f} MB")
    dense_passthrough_bytes = sum(v.nbytes for v in non_mat.values())

    # ── Variance analysis (one-time SVD to understand rank distribution) ──────
    print(f"\n-- Singular value variance analysis (rank needed for 99.9% / 99.99% energy) --")
    rank_999  = {}
    rank_9999 = {}
    for name, W in mat2d.items():
        rank_999[name]  = variance_rank(W, 0.999)
        rank_9999[name] = variance_rank(W, 0.9999)

    r999_vals  = list(rank_999.values())
    r9999_vals = list(rank_9999.values())
    print(f"  99.9%  energy: mean={np.mean(r999_vals):.1f} "
          f"median={np.median(r999_vals):.0f} "
          f"p95={np.percentile(r999_vals,95):.0f} "
          f"max={max(r999_vals)} min={min(r999_vals)}")
    print(f"  99.99% energy: mean={np.mean(r9999_vals):.1f} "
          f"median={np.median(r9999_vals):.0f} "
          f"p95={np.percentile(r9999_vals,95):.0f} "
          f"max={max(r9999_vals)} min={min(r9999_vals)}")

    # ── Per-type: how many unique shapes and rank distributions ───────────────
    print(f"\n-- Tensor type breakdown (2D only) --")
    type_counts: Dict[str, int] = {}
    type_bytes: Dict[str, int] = {}
    type_r999: Dict[str, List[int]] = {}
    for name, W in mat2d.items():
        t = classify_tensor(name, W.ndim)
        type_counts[t] = type_counts.get(t, 0) + 1
        type_bytes[t]  = type_bytes.get(t, 0) + W.nbytes
        type_r999.setdefault(t, []).append(rank_999[name])
    for t in sorted(type_counts):
        rs = type_r999[t]
        print(f"  {t:12s}: {type_counts[t]:3d} tensors  "
              f"{type_bytes[t]/1e6:6.1f} MB  "
              f"r999 mean={np.mean(rs):.1f} min={min(rs)} max={max(rs)}")

    # ── Main sweep ────────────────────────────────────────────────────────────
    print(f"\n{'─'*80}")
    print(f"SWEEP: k ∈ {RANKS}  variance_thresholds {VARIANCE_THRESHOLDS}")
    print(f"{'─'*80}")

    # Header row
    hdr = (f"{'k':>5}  {'vt':>7}  "
           f"{'GKQ_MB':>8}  {'ratio':>6}  "
           f"{'mean_err':>9}  {'p95_err':>8}  {'max_err':>8}  "
           f"{'mean_cos':>9}  "
           f"{'note'}")
    print(hdr)
    print("─" * len(hdr))

    results = []

    for k in RANKS:
        for vt in VARIANCE_THRESHOLDS:
            errs = []
            coss = []
            gkq_spectral_bytes = 0

            for name, W in mat2d.items():
                W32 = W.astype(np.float32)
                # Clamp k to matrix dimensions
                k_eff = min(k, min(W32.shape))
                # Also clamp to variance-threshold rank if smaller
                vt_rank = variance_rank(W32, vt)
                k_use = min(k_eff, vt_rank) if vt < 1.0 else k_eff

                U_q8, s_q8, Vt_q8, u_max, s_max, v_max = gkq_quantize_at_rank(W32, k_use)
                W_recon = gkq_reconstruct(U_q8, s_q8, Vt_q8, u_max, s_max, v_max)

                errs.append(rel_frob(W32, W_recon))
                coss.append(cosine_sim(W32, W_recon))

                k_actual = U_q8.shape[1]  # may be less than k if matrix small
                gkq_spectral_bytes += gkq_bytes_for_tensor(W32.shape, k_actual)

            total_gkq_bytes = gkq_spectral_bytes + dense_passthrough_bytes
            ratio = total_fp32_bytes / total_gkq_bytes

            mean_err = float(np.mean(errs))
            p95_err  = float(np.percentile(errs, 95))
            max_err  = float(np.max(errs))
            mean_cos = float(np.mean(coss))
            gkq_mb   = total_gkq_bytes / 1e6

            note = ""
            if mean_err < 0.01:
                note = "<1% mean — near-lossless"
            elif mean_err < 0.05:
                note = "<5% mean — usable"
            elif mean_err < 0.20:
                note = "<20% — lossy"
            else:
                note = "DEGRADE"

            print(f"  k={k:3d}  vt={vt:.4f}  "
                  f"gkq={gkq_mb:7.2f}MB  {ratio:5.2f}x  "
                  f"err_mean={mean_err:.5f}  p95={p95_err:.5f}  max={max_err:.5f}  "
                  f"cos={mean_cos:.5f}  {note}")

            results.append({
                "k": k, "vt": vt,
                "gkq_mb": gkq_mb, "ratio": ratio,
                "mean_err": mean_err, "p95_err": p95_err, "max_err": max_err,
                "mean_cos": mean_cos,
            })

    # ── Per-tensor-type error at production k=3 (old default) and k=64 (best) ──
    print(f"\n-- Per-tensor-type error at k=3 (old default) and k=64 (max tested) --")
    for k in [3, 64]:
        print(f"  k={k}:")
        type_errs: Dict[str, List[float]] = {}
        for name, W in mat2d.items():
            W32 = W.astype(np.float32)
            k_eff = min(k, min(W32.shape))
            U_q8, s_q8, Vt_q8, u_max, s_max, v_max = gkq_quantize_at_rank(W32, k_eff)
            W_recon = gkq_reconstruct(U_q8, s_q8, Vt_q8, u_max, s_max, v_max)
            t = classify_tensor(name, W32.ndim)
            type_errs.setdefault(t, []).append(rel_frob(W32, W_recon))
        for t in sorted(type_errs):
            es = type_errs[t]
            print(f"    {t:12s}: mean={np.mean(es):.5f}  p95={np.percentile(es,95):.5f}  max={np.max(es):.5f}")

    # ── Worst individual tensors at k=64 ──────────────────────────────────────
    print(f"\n-- Worst 10 individual tensors at k=64 --")
    k = 64
    tensor_errs = []
    for name, W in mat2d.items():
        W32 = W.astype(np.float32)
        k_eff = min(k, min(W32.shape))
        U_q8, s_q8, Vt_q8, u_max, s_max, v_max = gkq_quantize_at_rank(W32, k_eff)
        W_recon = gkq_reconstruct(U_q8, s_q8, Vt_q8, u_max, s_max, v_max)
        e = rel_frob(W32, W_recon)
        tensor_errs.append((name, W32.shape, e, classify_tensor(name, 2)))
    tensor_errs.sort(key=lambda x: -x[2])
    for name, shape, e, t in tensor_errs[:10]:
        print(f"    {e:.5f}  {t:12s}  {str(shape):16s}  {name}")

    # ── Comparison to Q8 ─────────────────────────────────────────────────────
    q8_mb = Q8_SIZES.get("tiny" if "tiny" in model_name else "base", None)
    if q8_mb:
        print(f"\n-- Comparison to q8 baseline ({q8_mb} MB) --")
        # Find smallest k where mean_err < 0.01
        frontier = None
        for r in results:
            if r["mean_err"] < 0.01 and r["vt"] == 0.999:
                if frontier is None or r["gkq_mb"] < frontier["gkq_mb"]:
                    frontier = r
        if frontier:
            print(f"  Smallest k where mean_err<1%: k={frontier['k']}  "
                  f"size={frontier['gkq_mb']:.2f} MB  "
                  f"vs q8={q8_mb} MB  "
                  f"ratio-vs-q8={q8_mb/frontier['gkq_mb']:.2f}x")
        else:
            print(f"  No k achieves mean_err<1% at vt=0.999")
        # Find even k=64 numbers for comparison
        k64 = next((r for r in results if r["k"]==64 and r["vt"]==0.999), None)
        if k64:
            print(f"  k=64 (max tested): size={k64['gkq_mb']:.2f} MB  "
                  f"vs q8={q8_mb} MB  "
                  f"gkq/q8={k64['gkq_mb']/q8_mb:.2f}x  "
                  f"mean_err={k64['mean_err']:.5f}")

    print(f"\n{'='*80}")
    print(f"END {model_name}")
    print(f"{'='*80}\n")


# ── Entrypoint ────────────────────────────────────────────────────────────────

def main():
    print("GKQ REAL WHISPER WEIGHT QUALITY SWEEP")
    print("Using signed offset-128 uint8 quantization (gkq_v2_format.reconstruct_spectral path)")
    print()

    # Always run tiny
    if not TINY_PATH.exists():
        print(f"ERROR: whisper-tiny weights not found at {TINY_PATH}", file=sys.stderr)
        sys.exit(1)
    sweep_model("whisper-tiny", TINY_PATH)

    # Run base only if already present
    if BASE_PATH.exists():
        sweep_model("whisper-base", BASE_PATH)
    else:
        print(f"whisper-base not present at {BASE_PATH} — skipping (as instructed).")


if __name__ == "__main__":
    main()
